import { useState, useEffect, useCallback, useRef } from "react";
import { format } from "date-fns";

export interface PricePoint {
  timestamp: number;
  time: string;
  price: number;
}

export interface BtcStats {
  current: number;
  high: number;
  low: number;
  changePercent: number;
  changeAbs: number;
}

export interface BtcData {
  points: PricePoint[];
  stats: BtcStats;
}

export function useBtcData(refreshInterval = 120_000) {
  const [data, setData] = useState<BtcData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const fetchData = useCallback(async (isRetry = false) => {
    if (!isRetry && !data) setLoading(true);
    setError(null);

    try {
      const apiUrl = "https://api.coingecko.com/api/v3/coins/bitcoin/market_chart?vs_currency=usd&days=1";
      const res = await fetch("/api/proxy?url=" + encodeURIComponent(apiUrl));

      if (!res.ok) {
        throw new Error(`API returned ${res.status}: ${res.statusText}`);
      }

      const json = await res.json();

      if (!json.prices || !Array.isArray(json.prices) || json.prices.length === 0) {
        throw new Error("Invalid data format received");
      }

      const points: PricePoint[] = json.prices.map(([ts, price]: [number, number]) => ({
        timestamp: ts,
        time: format(new Date(ts), "HH:mm"),
        price: price,
      }));

      const prices = points.map((p) => p.price);
      const high = Math.max(...prices);
      const low = Math.min(...prices);
      const current = prices[prices.length - 1];
      const first = prices[0];
      const changeAbs = current - first;
      const changePercent = ((current - first) / first) * 100;

      setData({ points, stats: { current, high, low, changePercent, changeAbs } });
      setLastUpdated(new Date());
    } catch (err: any) {
      setError(err.message || "Failed to fetch BTC data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    intervalRef.current = setInterval(() => fetchData(), refreshInterval);
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [fetchData, refreshInterval]);

  const retry = useCallback(() => {
    setLoading(true);
    fetchData(false);
  }, [fetchData]);

  return { data, loading, error, lastUpdated, retry };
}

