import React from "react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";
import { format } from "date-fns";
import type { PricePoint } from "../hooks/useBtcData";

function fmtUsd(n: number) {
  return n.toLocaleString("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

function CustomTooltip({ active, payload }: any) {
  if (!active || !payload?.length) return null;
  const point = payload[0].payload as PricePoint;
  return (
    <div className="bg-zinc-800 border border-zinc-700 px-3 py-2 shadow-lg">
      <p className="text-zinc-400 text-xs mb-1">
        {format(new Date(point.timestamp), "MMM dd, yyyy HH:mm")}
      </p>
      <p className="text-white text-sm font-bold" style={{ fontFamily: "monospace" }}>
        {fmtUsd(point.price)}
      </p>
    </div>
  );
}

interface ChartProps {
  points: PricePoint[];
  isUp: boolean;
}

export default function Chart({ points, isUp }: ChartProps) {
  const prices = points.map((p) => p.price);
  const min = Math.min(...prices);
  const max = Math.max(...prices);
  const padding = (max - min) * 0.08;
  const yMin = min - padding;
  const yMax = max + padding;

  const gradientId = "btcGradient";
  const strokeColor = isUp ? "#34d399" : "#f87171";
  const gradientStart = isUp ? "#34d399" : "#f87171";
  const gradientEnd = isUp ? "rgba(52,211,153,0)" : "rgba(248,113,113,0)";

  // Show ~8 tick labels on x-axis
  const tickInterval = Math.max(1, Math.floor(points.length / 8));

  return (
    <ResponsiveContainer width="100%" height="100%">
      <AreaChart data={points} margin={{ top: 4, right: 4, left: 0, bottom: 0 }}>
        <defs>
          <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={gradientStart} stopOpacity={0.35} />
            <stop offset="95%" stopColor={gradientEnd} stopOpacity={0} />
          </linearGradient>
        </defs>
        <CartesianGrid
          strokeDasharray="3 3"
          stroke="rgba(255,255,255,0.06)"
          vertical={false}
        />
        <XAxis
          dataKey="time"
          tick={{ fill: "#71717a", fontSize: 11, fontFamily: "monospace" }}
          axisLine={{ stroke: "rgba(255,255,255,0.08)" }}
          tickLine={false}
          interval={tickInterval}
          dy={6}
        />
        <YAxis
          domain={[yMin, yMax]}
          tick={{ fill: "#71717a", fontSize: 11, fontFamily: "monospace" }}
          axisLine={false}
          tickLine={false}
          tickFormatter={(v: number) =>
            v >= 1000 ? `$${(v / 1000).toFixed(1)}k` : `$${v.toFixed(0)}`
          }
          width={62}
          dx={-4}
        />
        <Tooltip content={<CustomTooltip />} cursor={{ stroke: "rgba(255,255,255,0.15)" }} />
        <Area
          type="monotone"
          dataKey="price"
          stroke={strokeColor}
          strokeWidth={2}
          fill={`url(#${gradientId})`}
          animationDuration={800}
          dot={false}
          activeDot={{ r: 4, fill: strokeColor, stroke: "#18181b", strokeWidth: 2 }}
        />
      </AreaChart>
    </ResponsiveContainer>
  );
}

